  ('aboriginal-f0899a01-moex-00301', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於立法院對於行政命令之審查程序，下列敘述何者正確？', '["行政命令須事前函請立法院同意後，始生效力", "僅有緊急命令須送立法院審查，其餘命令類型毋庸為之", "經立法院院會決議通知更正之命令，原訂頒機關逾期未更正者，該命令失效", "應送交立法院公告周知，由權利受影響之人民在期限內向立法院表示意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
