  ('aboriginal-f0899a01-moex-00305', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["行政機關於構成要件實現時，得選擇不同之法律效果，為裁量行政", "行政機關依法行使裁量權時，除有裁量瑕疵之情事外，法院不得審查", "行政裁量應受一般法律原則之拘束", "對於學生之成績評量或品行考核，為行政裁量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00306', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何種行政處分之瑕疵，無法於訴願程序終結前補正？', '["應記明理由而未記明者", "依法應舉行聽證而未舉行者", "應參與行政處分作成之委員會而未參與作成決議者", "應參與行政處分作成之其他機關而未參與者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
